<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller;use App\Models\SchoolClass;use App\Services\ReportService;use Dompdf\Dompdf;use Illuminate\Http\Request;use PhpOffice\PhpSpreadsheet\Spreadsheet;use PhpOffice\PhpSpreadsheet\Writer\Xlsx;
class ReportController extends Controller {
 public function index(Request $r,ReportService $s){$f=$r->only('from','to','class_id','status');$items=$s->query($f)->paginate(25)->withQueryString();return view('admin.reports.index',['items'=>$items,'classes'=>SchoolClass::orderBy('name')->get(),'filters'=>$f]);}
 public function pdf(Request $r,ReportService $s){$items=$s->query($r->only('from','to','class_id','status'))->get();$html=view('admin.reports.pdf',compact('items'))->render();$pdf=new Dompdf(['isRemoteEnabled'=>true]);$pdf->loadHtml($html);$pdf->setPaper('A4','landscape');$pdf->render();return response($pdf->output(),200,['Content-Type'=>'application/pdf','Content-Disposition'=>'attachment; filename="rekap-absensi.pdf"']);}
 public function excel(Request $r,ReportService $s){$items=$s->query($r->only('from','to','class_id','status'))->get();$x=new Spreadsheet();$sh=$x->getActiveSheet();$sh->fromArray(['No','Tanggal','Waktu','NIS','Nama Siswa','Kelas','Mata Pelajaran','Guru','Status'],null,'A1');$row=2;foreach($items as $i=>$a){$sh->fromArray([$i+1,$a->scanned_at?->format('d-m-Y'),$a->scanned_at?->format('H:i:s'),$a->student->nis,$a->student->user->name,$a->student->schoolClass->name,$a->session->subject->name,$a->session->teacher->user->name,ucfirst($a->status)],null,'A'.$row++);}foreach(range('A','I')as$c)$sh->getColumnDimension($c)->setAutoSize(true);$tmp=tempnam(sys_get_temp_dir(),'xlsx');(new Xlsx($x))->save($tmp);return response()->download($tmp,'rekap-absensi.xlsx')->deleteFileAfterSend(true);}
}
